GATHER_RESOURCE = 'https://management.core.windows.net'

def mknext(url, prevurl):
    if url.startswith('https://'):
        # Absolute URL
        return url
    raise ValueError('Unsupported nextLink value %s, exiting', url)

async def dumphelper(url, method=requests.get):
    global urlcounter, tokencounter
    nexturl = url
    while nexturl:
        checktoken()
        try:
            urlcounter += 1
            async with method(nexturl, headers=headers) as req:
                # Hold off when rate limit is reached
                if req.status == 429:
                    if tokencounter > 0:
                        tokencounter -= 10*MAX_REQ_PER_SEC
                        print('Sleeping because of rate-limit hit')
                    continue
                if req.status != 200:
                    print('Error %d for URL %s' % (req.status, nexturl))
                    # print(await req.text())
                    # print(req.headers)
                    print('')

                await azratelimit(req.headers)
                try:
                    objects = await req.json()
                except json.decoder.JSONDecodeError:
                    # In case we break Azure
                    print(url)
                    print(req.content)
                    print('')
                    return
                try:
                    nexturl = mknext(objects['nextLink'], url)
                except KeyError:
                    nexturl = None
                try:
                    for robject in objects['value']:
                        yield robject
                except KeyError:
                    # print(objects)
                    pass
        except Exception as exc:
            print(exc)
            return

def checktoken():
    global token, expiretime
    if time.time() > expiretime - 300:
        auth = Authentication()
        try:
            auth.client_id = token['_clientId']
        except KeyError:
            auth.client_id = '04b07795-8ddb-461a-bbee-02f9e1bf7b46'
        auth.tenant = token['tenantId']
        auth.tokendata = token
        auth.resource_uri = GATHER_RESOURCE
        if 'useragent' in token:
            auth.set_user_agent(token['useragent'])
        if 'originheader' in token:
            auth.set_origin_value(token['originheader'])
        if 'refreshToken' in token:
            print("Access token expired - fetching new token using refresh token")
            token = auth.authenticate_with_refresh_native(token)
            headers['Authorization'] = '%s %s' % (token['tokenType'], token['accessToken'])
            expiretime = time.time() + token['expiresIn']
            return True
        elif time.time() > expiretime:
            print('Access token is expired, but no access to refresh token! Dumping will fail')
            return False
    return True

def commit(session, dbtype, cache, ignore=False):
    global dburl
    if 'postgresql' in dburl and ignore:
        insertst = pginsert(dbtype.__table__)
        statement = insertst.on_conflict_do_nothing(
            index_elements=['objectId']
        )
    elif 'sqlite' in dburl and ignore:
        statement = dbtype.__table__.insert().prefix_with('OR IGNORE')
    else:
        statement = dbtype.__table__.insert()
    session.execute(
        statement,
        cache
    )

def commitlink(session, cachedict, ignore=False):
    global dburl
    for linktable, cache in cachedict.items():
        if 'postgresql' in dburl and ignore:
            insertst = pginsert(linktable)
            statement = insertst.on_conflict_do_nothing(
                index_elements=['objectId']
            )
        elif 'sqlite' in dburl and ignore:
            statement = linktable.insert().prefix_with('OR IGNORE')
        else:
            statement = linktable.insert()
        # print(cache)
        session.execute(
            statement,
            cache
        )


class DataDumper(object):
    def __init__(self, tenantid, api_version, ahsession=None, engine=None, session=None):
        self.api_version = api_version
        self.tenantid = tenantid
        self.session = session
        self.engine = engine
        self.ahsession = ahsession

    async def dump_subscription_roleassignments(self, subscription):
        cache = []
        rdprefix = f"/subscriptions/{subscription['subscriptionId']}/"
        raurl = f"https://management.azure.com/subscriptions/{subscription['subscriptionId']}/providers/Microsoft.Authorization/roleAssignments?api-version=2022-04-01"
        async for roleassignment in dumphelper(raurl, method=self.ahsession.get):
            roleassignment['properties']['roleDefinitionId'] = roleassignment['properties']['roleDefinitionId'].replace(rdprefix,'/')
            cache.append(az_role_assignment_from_json(roleassignment))
        commit(self.session, AZroleAssignment, cache, ignore=True)
        cache = []
        rdprefix = f"/subscriptions/{subscription['subscriptionId']}/"
        raurl = f"https://management.azure.com/subscriptions/{subscription['subscriptionId']}/providers/Microsoft.Authorization/roleEligibilityScheduleInstances?api-version=2020-10-01"
        async for eligibleroleassignment in dumphelper(raurl, method=self.ahsession.get):
            eligibleroleassignment['properties']['roleDefinitionId'] = eligibleroleassignment['properties']['roleDefinitionId'].replace(rdprefix,'/')
            jera = az_role_eligibility_schedule_instance_from_json(eligibleroleassignment)
            cache.append(jera)

        commit(self.session, AZroleEligibilityScheduleInstance, cache, ignore=True)

    async def query_resources(self, subscriptions, query):
        payload = {
            'query': query,
            'subscriptions': subscriptions
        }
        skip_token = 'initial'
        while skip_token:
            if skip_token != 'initial':
                payload['options'] = {
                    '$skipToken': skip_token
                }
            rurl = "https://management.azure.com/providers/Microsoft.ResourceGraph/resources?api-version=2021-03-01"
            await azratelimit()
            async with self.ahsession.post(rurl, headers=headers, json=payload) as response:
                if response.status != 200:
                    await azratelimit(response.headers)
                    if response.status == 429:
                        # retry
                        continue
                    print(await response.text())
                    print(f"rsp status {response.status}")
                    return
                data = await response.json()
                skip_token = data.get('$skipToken')
                for resource in data['data']:
                    yield resource

