def split_list(input_list, chunk_size):
    return [input_list[i:i + chunk_size] for i in range(0, len(input_list), chunk_size)]

IS_RATELIMITING = False
async def azratelimit(headers=None):
    global IS_RATELIMITING
    if headers and 'x-ms-user-quota-remaining' in headers:
        if int(headers['x-ms-user-quota-remaining']) < 1:
            # Handles ratelimit for this request
            IS_RATELIMITING = True
            # print('I AM THE RATELIMITER')
            await asyncio.sleep(5)
            IS_RATELIMITING = False
    elif IS_RATELIMITING:
        # other aio function is ratelimiting
        while IS_RATELIMITING:
            # print('Somebody else is ratelimiting')
            await asyncio.sleep(1)

