def json_to_subscription(json_data):
    subscription = AZsubscription(
        id=json_data.get("id"),
        subscription_id=json_data.get("subscriptionId"),
        display_name=json_data.get("displayName"),
        state=json_data.get("state"),
        subscription_policies=json_data.get("subscriptionPolicies"),
        authorization_source=json_data.get("authorizationSource"),
    )
    return subscription

def json_to_management_group(json_data):
    management_group = AZmanagementGroup(
        id=json_data.get("id"),
        name=json_data.get("name"),
        type=json_data.get("type"),
        display_name=json_data.get("displayName"),
        tenant_id=json_data.get("tenantId"),
        details=json_data.get("details"),
    )
    return management_group

async def run(args):
    global token, expiretime, headers, dburl
    if 'tenantId' in token:
        tenantid = token['tenantId']
    elif args.tenant:
        tenantid = args.tenant
    else:
        tenantid = 'myorganization'
    expiretime = time.mktime(time.strptime(token['expiresOn'].split('.')[0], '%Y-%m-%d %H:%M:%S'))
    headers = {
        'Authorization': '%s %s' % (token['tokenType'], token['accessToken'])
    }
    if args.user_agent:
        # Alias support, get temp auth object
        auth = Authentication()
        auth.set_user_agent(args.user_agent)
        headers['User-Agent'] = auth.user_agent
        # Store this in the token as well
        token['useragent'] = auth.user_agent

    if not checktoken():
        return
    # Recreate DB

    destroy_db = False

    engine = database.init(destroy_db, dburl=dburl)

    Session = sessionmaker(bind=engine)
    Base.metadata.create_all(engine)
    dbsession = Session()

    # Clear previous data

    dbsession.query(AZroleDefinition).delete()
    dbsession.query(AZroleAssignment).delete()
    dbsession.query(AZsubscription).delete()
    dbsession.query(AZmanagementGroup).delete()
    dbsession.query(AZroleEligibilityScheduleInstance).delete()
    dbsession.query(AZresource).delete()

    dumper = DataDumper(tenantid, '1.61-internal', engine=engine)
    async with aiohttp.ClientSession() as ahsession:
        print('Starting data gathering phase 1 of 2 (collecting objects)')
        dumper.ahsession = ahsession
        dumper.session = dbsession
        url = 'https://management.azure.com/providers/Microsoft.Authorization/roleDefinitions?api-version=2015-06-01'
        cache = []
        async for rd in dumphelper(url, method=ahsession.get):
            cache.append(az_role_definition_from_json(rd))
        commit(dbsession, AZroleDefinition, cache, ignore=True)

        tasks = []
        url = 'https://management.azure.com/subscriptions?api-version=2024-11-01'
        all_subscriptions = []
        async for subscription in dumphelper(url, method=ahsession.get):
            # print(subscription)
            dbsession.add(json_to_subscription(subscription))
            tasks.append(dumper.dump_subscription_roleassignments(subscription))
            all_subscriptions.append(subscription['subscriptionId'])
        tasks.append(dumper.dump_resources(all_subscriptions))

        await asyncio.gather(*tasks)


    print('Phase 2 - calculate IAM permissions')
    linktable_mapping = {
        'Group': (lnk_az_roleassignment_group, 'AZroleAssignment', 'Group'),
        'User': (lnk_az_roleassignment_user, 'AZroleAssignment', 'User'),
        'ServicePrincipal': (lnk_az_roleassignment_serviceprincipal, 'AZroleAssignment', 'ServicePrincipal'),
    }
    linkcache = {}
    for roleassignment in dbsession.query(AZroleAssignment).all():
        linkobjecttype = roleassignment.principal_type
        try:
            linktable, leftcol, rightcol = linktable_mapping[linkobjecttype]
        except KeyError:
            print('Unsupported member type: %s ' % (str(linkobjecttype)))
            continue
        try:
            linkcache[linktable].append({leftcol: roleassignment.id, rightcol: roleassignment.principal_id})
        except KeyError:
            linkcache[linktable] = [{leftcol: roleassignment.id, rightcol: roleassignment.principal_id}]
    linktable_mapping = {
        'Group': (lnk_az_roleassignment_eligible_group, 'AZroleEligibilityScheduleInstance', 'Group'),
        'User': (lnk_az_roleassignment_eligible_user, 'AZroleEligibilityScheduleInstance', 'User'),
        'ServicePrincipal': (lnk_az_roleassignment_eligible_serviceprincipal, 'AZroleEligibilityScheduleInstance', 'ServicePrincipal'),
    }
    for roleassignment in dbsession.query(AZroleEligibilityScheduleInstance).all():
        linkobjecttype = roleassignment.principal_type
        try:
            linktable, leftcol, rightcol = linktable_mapping[linkobjecttype]
        except KeyError:
            print('Unsupported member type: %s ' % (str(linkobjecttype)))
            continue
        try:
            linkcache[linktable].append({leftcol: roleassignment.id, rightcol: roleassignment.principal_id})
        except KeyError:
            linkcache[linktable] = [{leftcol: roleassignment.id, rightcol: roleassignment.principal_id}]
    commitlink(dbsession, linkcache)

    dbsession.commit()
    dbsession.close()

def getargs(gather_parser):
    gather_parser.add_argument('-d',
                               '--database',
                               action='store',
                               help='Database file. Can be the local database name for SQLite, or an SQLAlchemy compatible URL such as postgresql+psycopg2://dirkjan@/roadtools. Default: roadrecon.db',
                               default='roadrecon.db')
    gather_parser.add_argument('-f',
                               '--tokenfile',
                               action='store',
                               help='File to read credentials from obtained by roadrecon auth',
                               default='.roadtools_auth')
    gather_parser.add_argument('--tokens-stdin',
                               action='store_true',
                               help='Read tokens from stdin instead of from disk')
    gather_parser.add_argument('--mfa',
                               action='store_true',
                               help='Dump MFA details (requires use of a privileged account)')
    gather_parser.add_argument('--skip-first-phase',
                               action='store_true',
                               help='Skip the first phase (assumes this has been previously completed)')
    gather_parser.add_argument('-t',
                               '--tenant',
                               action='store',
                               help='Tenant ID to gather, if this info is not stored in the token')
    gather_parser.add_argument('-ua', '--user-agent', action='store',
                                help='Custom user agent to use. By default aiohttp default user agent is used, and python-requests is used for token renewal')
    gather_parser.add_argument('--autotoken',
                               action='store_true',
                               help='Use refresh token to request access token for the required API automatically')

def main(args=None):
    global token, headers, dburl, urlcounter
    if args is None:
        parser = argparse.ArgumentParser(add_help=True, description='ROADrecon - Gather Azure AD information', formatter_class=argparse.RawDescriptionHelpFormatter)
        getargs(parser)
        args = parser.parse_args()
        if len(sys.argv) < 2:
            parser.print_help()
            sys.exit(1)
    if args.tokens_stdin:
        token = json.loads(sys.stdin.read())
    else:
        with open(args.tokenfile, 'r') as infile:
            token = json.load(infile)
    if not ':/' in args.database:
        if args.database[0] != '/':
            dburl = 'sqlite:///' + os.path.join(os.getcwd(), args.database)
        else:
            dburl = 'sqlite:///' + args.database
    else:
        dburl = args.database
    try:
        _, tokendata = Authentication.parse_accesstoken(token['accessToken'])
    except KeyError:
        print('No access token found in tokenfile')
        return
    if tokendata['aud'] not in ('https://management.core.windows.net', 'https://management.core.windows.net/', 'https://management.azure.com/', '00000002-0000-0000-c000-000000000000'):
        if args.autotoken:
            auth = Authentication()
            # Break out of nested client for this resource
            if '_clientId' in token and token['_clientId'] == 'c44b4083-3bb0-49c1-b47d-974e53cbdf3c' and '_nestedClientId' in token:
                del token['_nestedClientId']
            token = auth.handle_autotoken(token, args=args, resource=GATHER_RESOURCE)
        else:
            print(f"Wrong token audience, got {tokendata['aud']} but expected https://management.core.windows.net")
            print("Make sure to request a token with -r https://management.core.windows.net")
            return

    headers['Authorization'] = f"Bearer {token['accessToken']}"

    seconds = time.perf_counter()
    asyncio.run(run(args))
    elapsed = time.perf_counter() - seconds
    print("ROADrecon azgather executed in {0:0.2f} seconds and issued {1} HTTP requests.".format(elapsed, urlcounter))

if __name__ == "__main__":
    main()
